-- 重建表：created_at=创建时间，updated_at=更新时间（均为 YYYY-MM-DD HH:mm:ss 文本）
drop table if exists history_data;

create table history_data (
  id            int8 primary key,
  kind          text not null check (kind in ('people_list', 'session')),
  session_no    int,
  created_at    text,
  updated_at    text,
  settled       boolean not null default false,
  settled_at    text,
  participants  jsonb,
  rounds        jsonb,
  people        jsonb
);

create index history_data_session_no_idx
  on history_data (session_no desc)
  where kind = 'session';

alter table history_data enable row level security;

create policy "history_data_all" on history_data
  for all using (true) with check (true);

